// Transaction Class
class Transaction {
    var id: UUID = UUID()
    var amount: Double
    var type: String
    
    init(amount: Double, type: String) {
        self.amount = amount
        self.type = type
    }
}

// BankAccount Class
class BankAccount {
    var accountNumber: String
    var balance: Double
    var transactions: [Transaction] = []
    
    init(accountNumber: String, initialBalance: Double = 0.0) {
        self.accountNumber = accountNumber
        self.balance = initialBalance
    }
    
    func deposit(amount: Double) -> Bool {
        balance += amount
        return true
    }
    
    func withdraw(amount: Double) -> Bool {
        if amount > balance {
            return false
        }
        balance -= amount
        return true
    }
    
    func addTransaction(transaction: Transaction) {
        transactions.append(transaction)
    }
}

// Banking App Class
class BankingApp {
    var accounts: [BankAccount] = []
    let encryptionKey: String
    
    init() {
        self.encryptionKey = "EncryptionKey123"
    }
    
    func createAccount(accountNumber: String, initialBalance: Double) -> BankAccount? {
        guard let account = BankAccount(accountNumber: accountNumber, initialBalance: initialBalance) else {
            return nil
        }
        accounts.append(account)
        return account
    }
    
    func processTransaction(accountNumber: String, transactionType: String, amount: Double) -> Bool {
        guard let account = accounts.first(where: { $0.accountNumber == accountNumber }) else {
            return false
        }
        
        switch transactionType {
        case "deposit":
            return account.deposit(amount: amount)
        case "withdrawal":
            return account.withdraw(amount: amount)
        default:
            return false
        }
    }
    
    func displayAccountBalances() {
        for account in accounts {
            print("Account Number: \(account.accountNumber), Balance: \(String(format: "%.2f", account.balance))")
        }
    }
}

// Encryption and Decryption Functions
func encrypt(data: String) -> Data? {
    guard let encryptedData = try? AES.gcmEncrypt(
        data: Data(data.utf8),
        nonce: Data(AES.randomNonceData(ofLength: 12)),
        key: encryptionKey.data(using: .utf8)!
    ) else {
        return nil
    }
    return encryptedData
}

func decrypt(encryptedData: Data, key: String) -> String? {
    guard let decryptedData = try? AES.gcmDecrypt(
        ciphertext: encryptedData,
        nonce: Data(AES.randomNonceData(ofLength: 12)),
        key: key.data(using: .utf8)!
    ) else {
        return nil
    }
    return String(decoding: decryptedData, as: UTF8.self)
}

